function getStripe() {
  const key = process.env.STRIPE_SECRET_KEY;
  if (!key) throw new Error("STRIPE_SECRET_KEY not configured");
  return new Stripe(key);
}

export const appRouter = router({
  system: systemRouter,
  auth: router({
    me: publicProcedure.query(opts => opts.ctx.user),
    logout: publicProcedure.mutation(({ ctx }) => {
      const cookieOptions = getSessionCookieOptions(ctx.req);
      ctx.res.clearCookie(COOKIE_NAME, { ...cookieOptions, maxAge: -1 });
      return { success: true };
    }),
  }),

  shop: router({
    products: publicProcedure.query(() => {
      return Object.entries(PRODUCTS).map(([id, p]) => ({ id, ...p }));
    }),

    createCheckout: publicProcedure
      .input(z.object({
        productId: z.string(),
        cartItems: z.array(z.object({
          productId: z.string(),
          name: z.string(),
          price: z.number(),
        })).optional(),
        successUrl: z.string(),
        cancelUrl: z.string(),
      }))
      .mutation(async ({ input }) => {
        const stripe = getStripe();

        // Multi-item cart checkout
        const cartItems = input.cartItems && input.cartItems.length > 0
          ? input.cartItems
          : [{ productId: input.productId, name: PRODUCTS[input.productId]?.name ?? input.productId, price: PRODUCTS[input.productId]?.price ?? 399 }];

        const lineItems = cartItems.map((item) => {
          const product = PRODUCTS[item.productId];
          return {
            price_data: {
              currency: "usd" as const,
              product_data: {
                name: item.name,
                description: product?.description ?? "Digital greeting card — instant PDF download",
                images: product?.image ? [product.image] : [],
              },
              unit_amount: item.price,
            },
            quantity: 1,
          };
        });

        const totalCents = cartItems.reduce((sum, i) => sum + i.price, 0);
        const productIds = cartItems.map((i) => i.productId).join(",");

        const session = await stripe.checkout.sessions.create({
          payment_method_types: ["card"],
          line_items: lineItems,
          mode: "payment",
          allow_promotion_codes: true,
          success_url: `${input.successUrl}?session_id={CHECKOUT_SESSION_ID}&products=${encodeURIComponent(productIds)}`,
          cancel_url: input.cancelUrl,
          metadata: {
            productIds,
            itemCount: String(cartItems.length),
          },
        });

        const db = await getDb();
        if (db && session.id) {
          // Record each item as a separate order row
          for (const item of cartItems) {
            const product = PRODUCTS[item.productId];
            await db.insert(orders).values({
              stripeSessionId: session.id,
              productId: item.productId,
              productName: item.name,
              amountCents: item.price,
              status: "pending",
              canvaLink: product?.pdfLink || null,
            });
          }
        }

        return { url: session.url, sessionId: session.id };
      }),

    getSubscribers: adminProcedure
      .input(z.object({ page: z.number().int().min(1).default(1), pageSize: z.number().int().min(1).max(200).default(50) }).optional())
      .query(async ({ input }) => {
        const db = await getDb();
        if (!db) return { subscribers: [], total: 0 };
        const page = input?.page ?? 1;
        const pageSize = input?.pageSize ?? 50;
        const offset = (page - 1) * pageSize;
        const rows = await db
          .select()
          .from(newsletterSubscribers)
          .orderBy(newsletterSubscribers.createdAt)
          .limit(pageSize)
          .offset(offset);
        const countRows = await db.select({ count: newsletterSubscribers.id }).from(newsletterSubscribers);
        return { subscribers: rows, total: countRows.length };
      }),

    subscribeNewsletter: publicProcedure
      .input(z.object({ email: z.string().email(), source: z.string().optional() }))
      .mutation(async ({ input }) => {
        const db = await getDb();
        if (!db) return { success: false, message: "Service unavailable" };
        try {
          await db.insert(newsletterSubscribers).values({
            email: input.email,
            source: input.source ?? "order_success",
          });
          try {
            await notifyOwner({
              title: "New Newsletter Subscriber",
              content: `${input.email} signed up from ${input.source ?? "order_success"}.`,
            });
          } catch (_) { /* non-critical */ }
          return { success: true, message: "You're on the list!" };
        } catch (err: unknown) {
          // Duplicate email — already subscribed
          const msg = err instanceof Error ? err.message : "";
          if (msg.includes("Duplicate") || msg.includes("unique")) {
            return { success: true, message: "You're already subscribed!" };
          }
          throw err;
        }
      }),

    getRelatedProducts: publicProcedure
      .input(z.object({ productId: z.string() }))
      .query(({ input }) => {
        const source = PRODUCTS[input.productId];
        if (!source || source.category !== "individual_card") return { related: [] };

        const sourceCountry = source.country ?? "";
        const sourceCardType = source.cardType ?? "";

        // All individual cards excluding the purchased one
        const allCards = Object.entries(PRODUCTS).filter(
          ([id, p]) => id !== input.productId && p.category === "individual_card"
        );

        // 2 cards from same country, different cardType
        const sameCountry = allCards
          .filter(([, p]) => p.country === sourceCountry && p.cardType !== sourceCardType)
          .slice(0, 2)
          .map(([id, p]) => ({
            productId: id,
            name: p.name,
            image: p.image ?? "",
            price: p.price,
            country: p.country ?? "",
            cardType: p.cardType ?? "",
            reason: "same_country" as const,
          }));

        // 1 card from same cardType, different country
        const sameOccasion = allCards
          .filter(([, p]) => p.cardType === sourceCardType && p.country !== sourceCountry)
          .slice(0, 1)
          .map(([id, p]) => ({
            productId: id,
            name: p.name,
            image: p.image ?? "",
            price: p.price,
            country: p.country ?? "",
            cardType: p.cardType ?? "",
            reason: "same_occasion" as const,
          }));

        return { related: [...sameCountry, ...sameOccasion] };
      }),

    getOrders: adminProcedure
      .input(z.object({
        page: z.number().min(1).default(1),
        pageSize: z.number().min(1).max(100).default(50),
        status: z.enum(["all", "paid", "pending", "failed"]).default("all"),
      }))
      .query(async ({ input }) => {
        const db = await getDb();
        if (!db) return { orders: [], total: 0, totalRevenueCents: 0 };
        const { desc, sql } = await import("drizzle-orm");
        const offset = (input.page - 1) * input.pageSize;
        const whereClause = input.status === "all" ? undefined : eq(orders.status, input.status as "paid" | "pending" | "failed");
        const allOrders = await db.select().from(orders)
          .where(whereClause)
          .orderBy(desc(orders.createdAt))
          .limit(input.pageSize)
          .offset(offset);
        const [countRow] = await db.select({ count: sql<number>`count(*)` }).from(orders).where(whereClause);
        const [revenueRow] = await db.select({ total: sql<number>`coalesce(sum(amount_cents), 0)` }).from(orders).where(eq(orders.status, "paid"));
        return {
          orders: allOrders,
          total: Number(countRow?.count ?? 0),
          totalRevenueCents: Number(revenueRow?.total ?? 0),
        };
      }),

    /** ── Physical Print Checkout (Gelato) ──────────────────────────────── */
    createPrintCheckout: publicProcedure
      .input(z.object({
        wallArtId: z.string(),
        size: z.enum(["8x10", "11x14"]),
        shippingAddress: z.object({
          firstName: z.string().min(1),
          lastName: z.string().min(1),
          email: z.string().email(),
          phone: z.string().optional(),
          addressLine1: z.string().min(1),
          addressLine2: z.string().optional(),
          city: z.string().min(1),
          state: z.string().optional(),
          postCode: z.string().min(1),
          country: z.string().min(2).max(2),
        }),
        successUrl: z.string(),
        cancelUrl: z.string(),
      }))
      .mutation(async ({ input }) => {
        const art = WALL_ART_CATALOG[input.wallArtId];
        if (!art) throw new Error(`Unknown wall art product: ${input.wallArtId}`);

        const priceCents = PRINT_PRICES[input.size];
        if (!priceCents) throw new Error(`Unknown print size: ${input.size}`);

        const sizeLabel = input.size === "8x10" ? '8×10"' : '11×14"';
        const productName = `${art.name} — ${sizeLabel} Physical Print`;

        const stripe = getStripe();

        // Store shipping address in Stripe metadata so we can retrieve it after payment
        const shippingMeta = JSON.stringify(input.shippingAddress);

        const session = await stripe.checkout.sessions.create({
          payment_method_types: ["card"],
          line_items: [
            {
              price_data: {
                currency: "usd",
                product_data: {
                  name: productName,
                  description: `Physical wall art poster (${sizeLabel}). Printed and shipped by Gelato.`,
                  images: art.image ? [art.image] : [],
                },
                unit_amount: priceCents,
              },
              quantity: 1,
            },
          ],
          mode: "payment",
          allow_promotion_codes: true,
          success_url: `${input.successUrl}?session_id={CHECKOUT_SESSION_ID}&products=${encodeURIComponent(input.wallArtId)}&type=print`,
          cancel_url: input.cancelUrl,
          metadata: {
            orderType: "physical_print",
            wallArtId: input.wallArtId,
            printSize: input.size,
            shippingAddress: shippingMeta,
            productIds: input.wallArtId,
          },
        });

        // Record order in DB
        const db = await getDb();
        if (db && session.id) {
          await db.insert(orders).values({
            stripeSessionId: session.id,
            productId: input.wallArtId,
            productName,
            amountCents: priceCents,
            status: "pending",
            canvaLink: null,
          });
        }

        return { url: session.url, sessionId: session.id };
      }),

    /** ── Verify Payment & Fulfill Print Orders via Gelato ─────────────── */
    verifyPayment: publicProcedure
      .input(z.object({ sessionId: z.string(), products: z.string().optional() }))
      .query(async ({ input }) => {
        const stripe = getStripe();
        const session = await stripe.checkout.sessions.retrieve(input.sessionId);

        if (session.payment_status !== "paid") {
          return { success: false, downloads: [], productName: null, orderType: "digital" };
        }

        const db = await getDb();
        if (db) {
          await db.update(orders)
            .set({ status: "paid", customerEmail: session.customer_details?.email ?? null })
            .where(eq(orders.stripeSessionId, input.sessionId));
        }

        const orderType = session.metadata?.orderType ?? "digital";

        // ── Physical print order: submit to Gelato ──
        if (orderType === "physical_print") {
          const wallArtId = session.metadata?.wallArtId ?? "";
          const printSize = (session.metadata?.printSize ?? "8x10") as "8x10" | "11x14";
          const art = WALL_ART_CATALOG[wallArtId];
          const sizeLabel = printSize === "8x10" ? '8×10"' : '11×14"';

          let gelatoOrderId = "";
          let gelatoError = "";

          if (art && session.metadata?.shippingAddress) {
            try {
              const shippingAddress = JSON.parse(session.metadata.shippingAddress);
              const gelatoReq = buildGelatoOrderRequest({
                orderId: `wwb-${session.id.slice(-12)}`,
                customerEmail: session.customer_details?.email ?? shippingAddress.email,
                size: printSize,
                imageUrl: art.image,
                itemName: art.name,
                shippingAddress,
              });
              const gelatoRes = await createGelatoOrder(gelatoReq);
              gelatoOrderId = gelatoRes.id;
            } catch (err) {
              gelatoError = err instanceof Error ? err.message : "Gelato order failed";
              console.error("[Gelato] Order creation failed:", gelatoError);
            }
          }

          const gelatoMode = isGelatoLiveMode() ? "LIVE" : "DRAFT";
          try {
            await notifyOwner({
              title: `Physical Print Order [${gelatoMode}] — ${art?.name ?? wallArtId} (${sizeLabel})`,
              content: `Customer: ${session.customer_details?.email ?? "unknown"}. Gelato ${gelatoMode} order: ${gelatoOrderId || "FAILED — " + gelatoError}. Stripe session: ${session.id}`,
            });
          } catch (_) { /* non-critical */ }

          return {
            success: true,
            downloads: [],
            productName: `${art?.name ?? wallArtId} — ${sizeLabel} Physical Print`,
            orderType: "physical_print",
            gelatoOrderId,
          };
        }

        // ── Digital download order (existing flow) ──
        const productIds = (input.products ?? session.metadata?.productIds ?? "").split(",").filter(Boolean);
        const downloads = productIds.map((pid) => {
          const product = PRODUCTS[pid];
          const hasFile = !!(product?.pdfLink);
          return {
            productId: pid,
            productName: product?.name ?? pid,
            // Generate a signed, time-limited download token (24h validity)
            downloadToken: hasFile ? generateDownloadToken(pid, input.sessionId) : null,
            downloadUrl: hasFile ? `/api/download/${generateDownloadToken(pid, input.sessionId)}` : null,
          };
        });

        const totalCents = productIds.reduce((sum, pid) => sum + (PRODUCTS[pid]?.price ?? 0), 0);

        try {
          await notifyOwner({
            title: `New Sale: ${downloads.length} item${downloads.length > 1 ? "s" : ""} — $${(totalCents / 100).toFixed(2)}`,
            content: `Customer purchased: ${downloads.map((d) => d.productName).join(", ")}. Email: ${session.customer_details?.email ?? "unknown"}`,
          });
        } catch (_) { /* non-critical */ }

        return { success: true, downloads, productName: downloads[0]?.productName ?? null, orderType: "digital" };
      }),

    // ── Order History (for logged-in users) ──────────────────────────────
    myOrders: publicProcedure
      .query(async ({ ctx }) => {
        if (!ctx.user?.email) {
          return { orders: [] };
        }

        const db = await getDb();
        if (!db) return { orders: [] };

        const { desc } = await import("drizzle-orm");
        const userOrders = await db
          .select()
          .from(orders)
          .where(eq(orders.customerEmail, ctx.user.email))
          .orderBy(desc(orders.createdAt))
          .limit(100);

        // Generate fresh signed download tokens for paid orders
        const ordersWithTokens = userOrders.map((order) => {
          const product = PRODUCTS[order.productId];
          const hasFile = order.status === "paid" && !!(product?.pdfLink);
          return {
            id: order.id,
            productId: order.productId,
            productName: order.productName,
            amountCents: order.amountCents,
            status: order.status,
            createdAt: order.createdAt,
            downloadUrl: hasFile
              ? `/api/download/${generateDownloadToken(order.productId, order.stripeSessionId)}`
              : null,
          };
        });

        return { orders: ordersWithTokens };
      }),

    // ── Refresh Download Token ───────────────────────────────────────────
    refreshDownload: publicProcedure
      .input(z.object({ sessionId: z.string(), productId: z.string() }))
      .query(async ({ input }) => {
        // Verify the session was actually paid
        const stripe = getStripe();
        const session = await stripe.checkout.sessions.retrieve(input.sessionId);

        if (session.payment_status !== "paid") {
          return { downloadUrl: null, error: "Payment not confirmed" };
        }

        const product = PRODUCTS[input.productId];
        if (!product?.pdfLink) {
          return { downloadUrl: null, error: "Product not found" };
        }

        // Verify this product was part of the session
        const sessionProductIds = (session.metadata?.productIds ?? "").split(",");
        if (!sessionProductIds.includes(input.productId)) {
          return { downloadUrl: null, error: "Product not part of this order" };
        }

        const token = generateDownloadToken(input.productId, input.sessionId);
        return { downloadUrl: `/api/download/${token}`, error: null };
      }),
  }),
});

export type AppRouter = typeof appRouter;
